import ssl
import time
import machine
from umqtt.simple import MQTTClient

BROKER_IP = "192.168.1.100"
BROKER_PORT = 8883
CLIENT_ID = "esp32_sensor_01"
TOPIC = b"sensors/temp"

MQTT_USER = "sensor_device"
MQTT_PASS = "S3cur3P@ssw0rd!"

sensor = machine.ADC(machine.Pin(36))
sensor.atten(machine.ADC.ATTN_11DB)


def read_temperature():
    raw = sensor.read()
    voltage = raw * 3.3 / 4095
    temperature = (voltage - 0.5) * 100
    return round(temperature, 2)


def create_ssl_context():
    ssl_params = {
        "cert_reqs": ssl.CERT_REQUIRED,
        "ca_certs": "/certs/ca.pem",
        "certfile": "/certs/client.crt",
        "keyfile": "/certs/client.key",
    }
    return ssl_params


def connect_mqtt():
    ssl_params = create_ssl_context()

    client = MQTTClient(
        CLIENT_ID,
        BROKER_IP,
        port=BROKER_PORT,
        user=MQTT_USER,
        password=MQTT_PASS,
        keepalive=60,
        ssl=True,
        ssl_params=ssl_params,
    )

    client.connect()
    print("Connected to MQTT broker via TLS on {}:{}".format(BROKER_IP, BROKER_PORT))
    return client


def main():
    retry_count = 0
    max_retries = 10
    client = None

    while retry_count < max_retries:
        try:
            client = connect_mqtt()
            break
        except OSError as e:
            retry_count += 1
            print("Connection failed (attempt {}/{}): {}".format(retry_count, max_retries, e))
            time.sleep(5)

    if client is None:
        print("Failed to connect after {} attempts. Resetting...".format(max_retries))
        machine.reset()

    while True:
        try:
            temp = read_temperature()
            payload = '{{"device":"{}","temperature":{},"unit":"C"}}'.format(
                CLIENT_ID, temp
            )
            client.publish(TOPIC, payload.encode(), qos=1)
            print("Published: {}".format(payload))
            time.sleep(30)
        except OSError as e:
            print("Publish error: {}. Reconnecting...".format(e))
            try:
                client.disconnect()
            except Exception:
                pass
            time.sleep(5)
            try:
                client = connect_mqtt()
            except OSError as e:
                print("Reconnection failed: {}. Resetting...".format(e))
                machine.reset()


if __name__ == "__main__":
    main()